INSERT INTO courses (id, instructor_id, category_id, title, slug, description, level, thumbnail_url, status, rejection_reason, chat_enabled, submitted_at, published_at, created_at, updated_at, pending_update_at, deleted_at, draft_title, draft_description, draft_thumbnail_url, draft_level, change_summary, draft_rejection_reason) VALUES ('669edabb-a426-4247-ad75-2d8d168bc0a6', '00000000-0000-0000-0000-000000000002', NULL, 'Cấu Trúc Dữ Liệu & Giải Thuật Toàn Diện', 'cau-truc-du-lieu--giai-thuat-toan-dien', 'Khóa học hệ thống hóa kiến thức về cấu trúc dữ liệu và giải thuật, từ cơ chế lưu trữ bộ nhớ, cấu trúc tuyến tính (mảng, danh sách liên kết, stack, queue), bảng băm, cây/heap cho đến đồ thị và các thuật toán duyệt phổ biến (BFS/DFS). Phù hợp cho người chuẩn bị phỏng vấn kỹ thuật hoặc muốn củng cố nền tảng lập trình.', 'INTERMEDIATE', NULL, 'PUBLISHED', NULL, false, '2026-07-13T01:27:35.471835+00:00'::timestamptz, '2026-07-13T01:27:10.167522+00:00'::timestamptz, '2026-07-13T01:22:25.202590+00:00'::timestamptz, '2026-07-13T01:27:55.153221+00:00'::timestamptz, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO courses (id, instructor_id, category_id, title, slug, description, level, thumbnail_url, status, rejection_reason, chat_enabled, submitted_at, published_at, created_at, updated_at, pending_update_at, deleted_at, draft_title, draft_description, draft_thumbnail_url, draft_level, change_summary, draft_rejection_reason) VALUES ('4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', '00000000-0000-0000-0000-000000000002', NULL, 'Lập Trình Hướng Đối Tượng (OOP) & Nguyên Tắc SOLID', 'lap-trinh-huong-oi-tuong-oop--nguyen-tac-solid', 'Hệ thống hóa toàn diện kiến thức OOP: lớp, đối tượng, constructor, bốn tính chất cốt lõi (đóng gói, kế thừa, đa hình, trừu tượng), quản lý ngoại lệ và bộ nhớ, cùng 5 nguyên tắc thiết kế SOLID giúp mã nguồn linh hoạt, dễ bảo trì và mở rộng. Minh họa bằng Java.', 'INTERMEDIATE', NULL, 'PENDING', NULL, false, '2026-07-13T01:29:19.601341+00:00'::timestamptz, NULL, '2026-07-13T01:23:31.294737+00:00'::timestamptz, '2026-07-13T01:29:19.616493+00:00'::timestamptz, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO courses (id, instructor_id, category_id, title, slug, description, level, thumbnail_url, status, rejection_reason, chat_enabled, submitted_at, published_at, created_at, updated_at, pending_update_at, deleted_at, draft_title, draft_description, draft_thumbnail_url, draft_level, change_summary, draft_rejection_reason) VALUES ('67407332-b3c5-4f37-8559-d39404b0a5ef', '00000000-0000-0000-0000-000000000003', NULL, 'CSS Toàn Diện: Từ Cơ Bản Đến Nâng Cao', 'css-toan-dien-tu-co-ban-en-nang-cao', 'Khóa học tổng hợp kiến thức CSS: selector, box model, positioning, flexbox, responsive design và các kỹ thuật nâng cao thường gặp khi phỏng vấn hoặc làm việc thực tế — giúp xây dựng giao diện web chuẩn và linh hoạt trên mọi thiết bị.', 'BEGINNER', NULL, 'PENDING_UPDATE', NULL, false, '2026-07-13T01:30:03.381024+00:00'::timestamptz, '2026-07-13T01:29:42.258946+00:00'::timestamptz, '2026-07-13T01:24:42.519492+00:00'::timestamptz, '2026-07-13T01:30:03.389006+00:00'::timestamptz, '2026-07-13T01:30:03.381024+00:00'::timestamptz, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO courses (id, instructor_id, category_id, title, slug, description, level, thumbnail_url, status, rejection_reason, chat_enabled, submitted_at, published_at, created_at, updated_at, pending_update_at, deleted_at, draft_title, draft_description, draft_thumbnail_url, draft_level, change_summary, draft_rejection_reason) VALUES ('513ccfd5-8642-4286-b1ba-b85e6bc1a72f', '00000000-0000-0000-0000-000000000003', NULL, 'HTML & HTML5 Toàn Diện Cho Người Mới Bắt Đầu', 'html--html5-toan-dien-cho-nguoi-moi-bat-au', 'Khóa học toàn diện về HTML và HTML5: cú pháp thẻ/thuộc tính, cấu trúc tài liệu, tích hợp CSS/JavaScript, form nhập liệu, xử lý sự kiện, các tính năng nổi bật của HTML5 (Semantic Elements) và chuẩn SEO cơ bản.', 'BEGINNER', NULL, 'PUBLISHED', NULL, false, '2026-07-13T01:34:07.837243+00:00'::timestamptz, '2026-07-13T01:31:42.139115+00:00'::timestamptz, '2026-07-13T01:25:50.527226+00:00'::timestamptz, '2026-07-13T01:34:29.373432+00:00'::timestamptz, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Nội dung Core Web Vitals cần bổ sung ví dụ đo lường thực tế và số liệu cụ thể trước khi duyệt.');
INSERT INTO courses (id, instructor_id, category_id, title, slug, description, level, thumbnail_url, status, rejection_reason, chat_enabled, submitted_at, published_at, created_at, updated_at, pending_update_at, deleted_at, draft_title, draft_description, draft_thumbnail_url, draft_level, change_summary, draft_rejection_reason) VALUES ('60f3a98a-e216-4849-b72c-1e2edab7fd50', '00000000-0000-0000-0000-000000000002', NULL, 'Nhập Môn Lập Trình Web Frontend: HTML & CSS Căn Bản', 'nhap-mon-lap-trinh-web-frontend-html--css-can-ban', 'Khóa học nhập môn dành cho người mới bắt đầu, kết hợp kiến thức nền tảng về HTML và CSS để xây dựng trang web tĩnh đầu tiên — từ cấu trúc thẻ HTML cơ bản đến tạo layout bằng CSS.', 'BEGINNER', NULL, 'DRAFT', NULL, false, NULL, NULL, '2026-07-13T01:26:31.741882+00:00'::timestamptz, '2026-07-13T01:26:31.741882+00:00'::timestamptz, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
