INSERT INTO chapters (id, course_id, title, description, order_index, created_at, is_draft, pending_delete, deleted_at) VALUES ('1dff8c41-332a-4f31-a78d-2189fdb0fea6', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Layout Hiện Đại & Responsive', NULL, 2, '2026-07-13T01:24:42.645024+00:00'::timestamptz, false, false, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('87ec8bc7-24db-4f8c-86ff-d950da7cfe2a', 'fa18e0a9-1641-4b68-98c4-e8701e042717', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'SRP & OCP — Đơn Nhiệm Và Đóng/Mở', 1, 'TEXT', 'Single Responsibility Principle (SRP): một lớp chỉ nên giữ một trách nhiệm duy nhất — chỉ một lý do để thay đổi. Ví dụ vi phạm: lớp Invoice vừa tính tiền, vừa in ấn, vừa lưu database. Giải pháp: tách thành Invoice, InvoicePrinter, InvoiceRepository độc lập.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('dc51035f-330a-46c0-a0a9-4e438b654f7f', '78862408-0507-416a-9c2b-572f5dfb0a83', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'Lớp, Đối Tượng & Constructor', 1, 'TEXT', 'Lớp (Class) là bản thiết kế (blueprint) mô tả thuộc tính và phương thức mà đối tượng tạo ra từ nó sẽ sở hữu — bản thân lớp không chiếm bộ nhớ Heap, chỉ được tải vào Metaspace để lưu metadata cấu trúc. Đối tượng (Object) là thực thể cụ thể (instance) được tạo bằng từ khóa new, được cấp phát bộ nhớ trên Heap.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('a3509314-adc9-4ed2-b3d8-045294f7cdb7', '78862408-0507-416a-9c2b-572f5dfb0a83', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'Bốn Tính Chất Cốt Lõi Của OOP', 2, 'TEXT', 'Tính đóng gói (Encapsulation): che giấu chi tiết bên trong đối tượng, chỉ tiếp cận qua giao diện public — triển khai bằng private kết hợp Getter/Setter kèm logic kiểm tra.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('49bc8834-127f-41e3-88b6-9fffd525cf1b', 'fa18e0a9-1641-4b68-98c4-e8701e042717', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'LSP & ISP — Thay Thế Liskov Và Phân Tách Giao Diện', 2, 'TEXT', 'Liskov Substitution Principle (LSP): đối tượng lớp con phải thay thế hoàn toàn được cho lớp cha mà không làm sai tính đúng đắn chương trình. Ví dụ vi phạm kinh điển: lớp cha Bird có fly(), lớp con Ostrich (đà điểu) không biết bay nên phải ném exception — vi phạm hợp đồng của lớp cha. Giải pháp: tách nhỏ phân cấp, chỉ loài bay được mới kế thừa interface FlyingBird riêng.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('de85b397-d9d3-46c8-95d4-ac1c9b85570b', 'fa18e0a9-1641-4b68-98c4-e8701e042717', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'DIP — Đảo Ngược Phụ Thuộc & Tổng Kết SOLID', 3, 'TEXT', 'Dependency Inversion Principle (DIP): module cấp cao không nên phụ thuộc trực tiếp vào module cấp thấp — cả hai nên phụ thuộc vào tầng trừu tượng (Interface). Ví dụ vi phạm: lớp Car khởi tạo trực tiếp MySQLDatabase trong constructor, hardcode phụ thuộc. Giải pháp: định nghĩa interface Database, Car nhận vào một đối tượng Database qua Dependency Injection — các lớp cụ thể như MySQLDatabase, OracleDatabase implement interface đó.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('593bfb99-86d5-42e4-b6b3-4f985c095e59', '78862408-0507-416a-9c2b-572f5dfb0a83', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 'Ngoại Lệ & Quản Lý Bộ Nhớ (Garbage Collection)', 3, 'TEXT', 'Ngoại lệ (Exception) là sự kiện bất thường làm gián đoạn luồng chạy chương trình, chia làm Checked Exception (bắt buộc xử lý khi biên dịch) và Unchecked/Runtime Exception (xảy ra khi chạy). Xử lý bằng try (đoạn mã có nguy cơ lỗi) - catch (bắt và xử lý) - finally (luôn thực thi, dùng dọn tài nguyên); throw/throws dùng để ném hoặc chuyển tiếp trách nhiệm xử lý.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('b719af34-1f8e-443f-b79e-7f32e565a3ba', 'f986f514-b366-48f8-8033-bbcec134ab37', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Liên Kết & Tích Hợp CSS', 1, 'TEXT', 'Liên kết trong HTML dùng thẻ <a href="...">, thuộc tính target="_blank" mở liên kết ở tab mới. Có 3 cách tích hợp CSS với HTML: Inline CSS (viết trực tiếp trong thuộc tính style của thẻ, ưu tiên cao nhất nhưng khó bảo trì), Internal CSS (khai báo trong thẻ <style> ở phần <head>, áp dụng riêng cho trang đó), và External CSS (liên kết file .css riêng qua thẻ <link rel="stylesheet" href="...">, cách được khuyến nghị vì dễ tái sử dụng và bảo trì trên nhiều trang).
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('74d5acfb-9491-412c-86ff-477b4e95d528', '5af67cbf-eb3b-4802-a953-5248f4f0c8e3', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Tính Năng Mới Của HTML5 & Semantic Elements', 1, 'TEXT', 'HTML5 mang lại nhiều ưu điểm đột phá so với phiên bản trước: hỗ trợ đa phương tiện gốc (<video>, <audio>) không cần plugin Flash; các API mới (Canvas, Geolocation, Local Storage, Web Workers); cú pháp gọn nhẹ hơn (<!DOCTYPE html>); và đặc biệt là Semantic Elements — các thẻ mang ý nghĩa ngữ nghĩa rõ ràng về vai trò của khối nội dung thay vì chỉ dùng <div> chung chung: <header> (đầu trang), <nav> (menu điều hướng), <main> (nội dung chính), <article> (bài viết độc lập), <section> (một phần nội dung theo chủ đề), <aside> (nội dung phụ/sidebar), <footer> (chân trang). Semantic Elements giúp trình duyệt, công cụ tìm kiếm và trình đọc màn hình (screen reader) hiểu đúng cấu trúc và vai trò từng phần của trang, cải thiện đáng kể khả năng tiếp cận (accessibility) và SEO.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:25:51.733142+00:00'::timestamptz, '2026-07-13T01:25:51.733142+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('66a497f2-75f4-49f5-ba7d-5238ddc8c95d', 'd5667ba8-f384-4e63-9c99-afea364215e7', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Thẻ, Thuộc Tính & Các Thẻ Văn Bản Cơ Bản', 1, 'TEXT', 'Thẻ (Tag) là đơn vị cấu trúc cơ bản của HTML, thường đi theo cặp mở/đóng (<p></p>), một số thẻ tự đóng (<img />, <br />). Thuộc tính (Attribute) là thông tin bổ sung đặt trong thẻ mở, dạng name="value" (như src, href, class, id), cung cấp thêm dữ liệu hoặc điều khiển hành vi của phần tử.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('baf1626b-712e-49cc-8f67-7c2f162dbe1a', '5af67cbf-eb3b-4802-a953-5248f4f0c8e3', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'SEO & Cấu Trúc HTML Chuẩn', 2, 'TEXT', 'SEO (Search Engine Optimization) là tập hợp kỹ thuật giúp trang web được các công cụ tìm kiếm (Google...) đánh giá cao và xếp hạng tốt hơn trong kết quả tìm kiếm. Để có cấu trúc HTML chuẩn SEO, cần: sử dụng đúng phân cấp thẻ heading (chỉ một <h1> duy nhất cho tiêu đề chính, các heading con theo thứ tự h2, h3... không nhảy cóc); khai báo đầy đủ <meta name="description"> mô tả ngắn gọn nội dung trang; dùng Semantic Elements thay vì <div> tràn lan để công cụ tìm kiếm hiểu đúng cấu trúc; thêm thuộc tính alt cho mọi thẻ <img> (vừa hỗ trợ accessibility vừa giúp SEO hình ảnh); đảm bảo trang responsive (thân thiện di động) và tốc độ tải nhanh — đây đều là các yếu tố xếp hạng quan trọng của công cụ tìm kiếm hiện đại.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:25:51.763335+00:00'::timestamptz, '2026-07-13T01:33:35.356497+00:00'::timestamptz, false, false, NULL, 'SEO (Search Engine Optimization) là tập hợp kỹ thuật giúp trang web được các công cụ tìm kiếm (Google...) đánh giá cao và xếp hạng tốt hơn trong kết quả tìm kiếm. Để có cấu trúc HTML chuẩn SEO, cần: sử dụng đúng phân cấp thẻ heading (chỉ một <h1> duy nhất cho tiêu đề chính, các heading con theo thứ tự h2, h3... không nhảy cóc); khai báo đầy đủ <meta name="description"> mô tả ngắn gọn nội dung trang; dùng Semantic Elements thay vì <div> tràn lan để công cụ tìm kiếm hiểu đúng cấu trúc; thêm thuộc tính alt cho mọi thẻ <img> (vừa hỗ trợ accessibility vừa giúp SEO hình ảnh); đảm bảo trang responsive (thân thiện di động) và tốc độ tải nhanh — đây đều là các yếu tố xếp hạng quan trọng của công cụ tìm kiếm hiện đại.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('c547a43d-939e-46a8-9f23-7560b08d93b3', 'f986f514-b366-48f8-8033-bbcec134ab37', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Tích Hợp JavaScript & Xử Lý Sự Kiện', 2, 'TEXT', 'Có thể thêm JavaScript vào HTML qua 3 cách tương tự CSS: Inline (trong thuộc tính onclick...), Internal (trong thẻ <script> ngay trong trang), External (liên kết file .js riêng qua <script src="...">). Vị trí đặt thẻ <script>: nếu đặt trong <head>, trình duyệt phải tải và chạy xong script mới tiếp tục dựng trang (có thể làm chậm hiển thị) trừ khi dùng thuộc tính defer/async; đặt cuối <body> (trước </body>) là thông lệ phổ biến để đảm bảo toàn bộ DOM đã dựng xong trước khi script chạy, tránh lỗi truy cập phần tử chưa tồn tại.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('864dff1e-39c7-4ff0-a2e5-4e7f8db431f6', 'd5667ba8-f384-4e63-9c99-afea364215e7', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Cấu Trúc Head/Body, Bảng & Layout', 2, 'TEXT', 'Thẻ <head> chứa metadata không hiển thị trực tiếp trên trang (title, meta charset, meta viewport, liên kết CSS, SEO description) — quan trọng cho trình duyệt và công cụ tìm kiếm. Thẻ <body> chứa toàn bộ nội dung hiển thị thực sự cho người dùng (văn bản, hình ảnh, form, bảng...).
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('e7117251-ee52-48de-a867-329e0d7f394c', 'f986f514-b366-48f8-8033-bbcec134ab37', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 'Form & Các Kiểu Input', 3, 'TEXT', 'Form trong HTML dùng thẻ <form action="..." method="post|get"> để thu thập dữ liệu người dùng và gửi lên server. Các phần tử nhập liệu phổ biến: <input>, <textarea>, <select>, <button>. HTML5 bổ sung nhiều kiểu input mới giúp validate và trải nghiệm nhập liệu tốt hơn ngay từ trình duyệt mà không cần JavaScript: type="email" (kiểm tra định dạng email), type="date" (bộ chọn ngày), type="number" (chỉ nhập số, có nút tăng/giảm), type="range" (thanh trượt), type="tel", type="url", type="color"... Các thuộc tính bổ trợ như required, placeholder, pattern giúp tăng cường validate phía client trước khi gửi dữ liệu lên server.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:25:51.668963+00:00'::timestamptz, '2026-07-13T01:25:51.668963+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('32211052-d2d7-4512-988e-5d5b26414419', 'a3026185-cc45-49df-91f8-63e2444c0d84', '60f3a98a-e216-4849-b72c-1e2edab7fd50', 'Cấu Trúc Trang HTML Cơ Bản', 1, 'TEXT', 'Một trang HTML cơ bản bắt đầu bằng khai báo <!DOCTYPE html>, sau đó là thẻ <html> bao bọc toàn bộ trang, chia thành hai phần chính: <head> (chứa metadata như title, charset, không hiển thị trực tiếp) và <body> (chứa nội dung hiển thị thực sự). Các thẻ văn bản cơ bản gồm <h1>-<h6> cho tiêu đề, <p> cho đoạn văn, <ul>/<ol>/<li> cho danh sách không thứ tự/có thứ tự, <a href="..."> cho liên kết, <img src="..." alt="..."> cho hình ảnh. Thuộc tính (attribute) như class, id, src, href cung cấp thêm thông tin hoặc điều khiển hành vi cho thẻ.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:26:32.043160+00:00'::timestamptz, '2026-07-13T01:26:32.043160+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('ce424ba1-28f4-4f7a-9464-2f1c365a532c', '867fcc21-0cd2-4f47-a313-c2e34f7e6677', '60f3a98a-e216-4849-b72c-1e2edab7fd50', 'Selector & Box Model Căn Bản', 1, 'TEXT', 'CSS chọn phần tử để định dạng thông qua selector: theo thẻ (p { }), theo class (.ten-class { }), theo id (#ten-id { }). Mỗi phần tử HTML được trình duyệt hiển thị theo Box Model gồm 4 lớp từ trong ra ngoài: content (nội dung), padding (khoảng đệm trong viền), border (đường viền), margin (khoảng cách ngoài viền, tới phần tử khác). Nắm vững Box Model là bước đầu tiên và quan trọng nhất để kiểm soát khoảng cách và kích thước mọi phần tử trên trang.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:26:32.483632+00:00'::timestamptz, '2026-07-13T01:26:32.483632+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('281f7eb5-c468-4d6e-b3f9-dd8384113e10', '867fcc21-0cd2-4f47-a313-c2e34f7e6677', '60f3a98a-e216-4849-b72c-1e2edab7fd50', 'Layout Với Flexbox & Responsive Cơ Bản', 2, 'TEXT', 'Flexbox (display: flex trên phần tử cha) là cách đơn giản và phổ biến nhất hiện nay để sắp xếp các phần tử con theo hàng hoặc cột, với justify-content (căn theo trục chính) và align-items (căn theo trục chéo) giúp căn giữa nội dung dễ dàng chỉ với vài dòng CSS. Responsive Design giúp trang web hiển thị tốt trên cả máy tính lẫn điện thoại, thực hiện chủ yếu qua Media Query (@media (max-width: 768px) { ... }) để áp dụng style khác nhau tùy kích thước màn hình, kết hợp đơn vị tương đối (%, vw) thay vì đơn vị cố định (px).', NULL, false, NULL, NULL, NULL, '2026-07-13T01:26:32.510151+00:00'::timestamptz, '2026-07-13T01:26:32.510151+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('43151edd-a844-4a8f-874d-01fcf26e8f83', 'a3026185-cc45-49df-91f8-63e2444c0d84', '60f3a98a-e216-4849-b72c-1e2edab7fd50', 'Semantic Elements & Form Nhập Liệu', 2, 'TEXT', 'Semantic Elements của HTML5 giúp cấu trúc trang rõ ràng về mặt ý nghĩa: <header> (đầu trang), <nav> (menu), <main> (nội dung chính), <section>, <article>, <footer> (chân trang) — nên ưu tiên dùng thay vì <div> chung chung để cải thiện SEO và khả năng tiếp cận. Form nhập liệu dùng thẻ <form> bao ngoài, kết hợp <input type="text|email|number|...">, <textarea>, <button> để thu thập dữ liệu người dùng — các kiểu input hiện đại của HTML5 (email, date, number...) giúp trình duyệt tự validate dữ liệu ngay khi nhập, không cần viết thêm JavaScript.', NULL, false, NULL, NULL, NULL, '2026-07-13T01:26:32.423629+00:00'::timestamptz, '2026-07-13T01:26:32.423629+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('26a19336-2f67-48e2-a8eb-26be9e71f19f', '0aa5c6ac-65ad-4b5c-9731-c238a7afae86', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Bảng Băm (Hash Table)', 1, 'TEXT', 'HashMap là cấu trúc dữ liệu thuộc Java Collections Framework, lưu trữ theo cặp Key-Value, cho phép truy cập/thêm/xóa với hiệu năng trung bình O(1) nhờ cơ chế băm (Hashing). Cơ chế hoạt động: hàm hashCode() biến Key thành chỉ số (Index) để xếp vào các Bucket trong mảng ngầm định. Khi hai Key khác nhau cho cùng chỉ số, xảy ra Xung đột băm (Hash Collision) — Java giải quyết bằng Linked List tại bucket đó, và tự động nâng cấp thành Cây đỏ đen (Red-Black Tree) nếu số phần tử xung đột vượt quá 8 (từ Java 8) để giữ hiệu năng tìm kiếm O(log n).', NULL, false, NULL, NULL, NULL, '2026-07-13T01:22:25.727246+00:00'::timestamptz, '2026-07-13T01:22:25.727788+00:00'::timestamptz, false, false, NULL, NULL, NULL, NULL);
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('06300607-cc31-4ebb-b9c0-2e6f398b38a9', 'b102a7b9-251a-4a2a-b75f-84f5d9590fb3', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Cơ Chế Lưu Trữ Bộ Nhớ', 1, 'TEXT', 'Khi một biến được khai báo và khởi tạo, hệ thống trải qua 4 bước: (1) Xác định kiểu dữ liệu và kích thước byte cần thiết (int chiếm 4 bytes, double chiếm 8 bytes); (2) Cấp phát địa chỉ bộ nhớ — biến cục bộ và tham chiếu vào Stack (nhanh, tự giải phóng khi hết block lệnh), đối tượng và mảng vào Heap (vùng nhớ động, tồn tại lâu hơn); (3) Liên kết định danh và địa chỉ qua Symbol Table, ánh xạ tên biến với địa chỉ ô nhớ dạng Hexadecimal; (4) Ghi giá trị dưới dạng mã nhị phân vào các ô nhớ đã chỉ định. Hiểu rõ cơ chế Stack vs Heap là nền tảng để lý giải hiệu năng và vòng đời của mọi cấu trúc dữ liệu sau này.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('1f744d86-f8fa-47ce-b60a-13caa7b3a51c', 'b102a7b9-251a-4a2a-b75f-84f5d9590fb3', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Mảng & Danh Sách Liên Kết', 2, 'TEXT', 'Mảng (Array) là cấu trúc dữ liệu tuyến tính lưu các phần tử cùng kiểu tại các ô nhớ liên tiếp, kích thước cố định (Static). Truy cập ngẫu nhiên đạt O(1) nhờ công thức: Địa chỉ phần tử i = Địa chỉ gốc + i × kích thước kiểu dữ liệu. Mảng đa chiều thực chất là "mảng của mảng", được trải phẳng và lưu tuần tự theo Row-major hoặc Column-major trên RAM.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('8764e5c5-da90-49d9-8d51-e931a9cae20a', '0aa5c6ac-65ad-4b5c-9731-c238a7afae86', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Cây (Tree) & Heap', 2, 'TEXT', 'Cây là cấu trúc dữ liệu phi tuyến tính, phân cấp, gồm các Node nối bằng Edge, luôn có một Root Node duy nhất, các Node không có con gọi là Leaf Node. Cây nhị phân (Binary Tree): mỗi Node cha có tối đa 2 con (Left/Right Child). Cây tìm kiếm nhị phân (BST) thêm ràng buộc: giá trị cây con trái < giá trị nút cha ≤ giá trị cây con phải, giúp tìm kiếm/chèn/xóa đạt O(log n) khi cân bằng.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('8a9a37ee-ddd0-4303-9b92-f04711bcd1bc', '0aa5c6ac-65ad-4b5c-9731-c238a7afae86', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Đồ Thị (Graph) & Thuật Toán BFS/DFS', 3, 'TEXT', 'Đồ thị (Graph) gồm tập đỉnh (Vertices) và tập cạnh (Edges) nối các cặp đỉnh, có thể có hướng (Directed) hoặc vô hướng (Undirected). Ứng dụng: mạng xã hội, bản đồ/định vị, mạng máy tính, hệ thống gợi ý. Hai cách biểu diễn phổ biến: Ma trận kề (Adjacency Matrix — kiểm tra cạnh O(1) nhưng tốn O(V²) bộ nhớ) và Danh sách kề (Adjacency List — tối ưu bộ nhớ hơn cho đồ thị thưa).
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('a2abbfdd-763f-4594-b80a-1edbdd02b7c4', 'b102a7b9-251a-4a2a-b75f-84f5d9590fb3', '669edabb-a426-4247-ad75-2d8d168bc0a6', 'Ngăn Xếp (Stack) & Hàng Đợi (Queue)', 3, 'TEXT', 'Ngăn xếp (Stack) hoạt động theo nguyên lý LIFO (Last In, First Out) với 3 thao tác chính: push() (thêm vào đỉnh), pop() (xóa ở đỉnh), peek() (xem đỉnh mà không xóa). Ứng dụng thực tế: hàm đệ quy, tính năng Undo/Redo, kiểm tra tính hợp lệ của dấu ngoặc.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('0dc530be-7cdd-422e-a44a-9152c877e7a5', '895dc74d-15b8-41c9-bf59-84ac0ba51f5a', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Selector, Display & Box Model', 1, 'TEXT', 'CSS có nhiều loại selector: theo thẻ (tag), class (.name), id (#name), thuộc tính ([attr]), pseudo-class/pseudo-element, và các bộ kết hợp (combinator) như khoảng trắng (descendant), > (child), + (adjacent sibling). Thuộc tính color quy định màu chữ/nội dung, trong khi background-color quy định màu nền của phần tử — hai khái niệm độc lập.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('6844daba-1ee9-425a-8cc6-85a043b5cf5a', '1dff8c41-332a-4f31-a78d-2189fdb0fea6', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Flexbox & Responsive Design', 1, 'TEXT', 'Flexbox là hệ thống dàn trang một chiều (hàng hoặc cột), kích hoạt bằng display: flex trên container. Với flex-direction: row (mặc định): justify-content căn chỉnh các phần tử dọc theo trục chính (Main axis, chiều ngang trái-phải); align-items căn chỉnh dọc theo trục chéo (Cross axis, chiều dọc trên-dưới).
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('a8681dff-b3c2-4ec0-ae08-40500780abcc', '895dc74d-15b8-41c9-bf59-84ac0ba51f5a', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Positioning & Z-index', 2, 'TEXT', 'Thuộc tính position có 5 giá trị: static (mặc định, theo luồng tài liệu), relative (dịch chuyển so với vị trí gốc của chính nó, vẫn giữ chỗ trong layout), absolute (định vị so với ancestor gần nhất có position khác static, thoát khỏi luồng tài liệu), fixed (định vị so với viewport, cố định khi cuộn trang), sticky (kết hợp relative và fixed, dính lại khi cuộn qua ngưỡng chỉ định).
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('d2284f9e-2c02-4458-b512-c8fa925356e8', '1dff8c41-332a-4f31-a78d-2189fdb0fea6', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Pseudo-elements, CSS Variables & Đơn Vị', 2, 'TEXT', 'Pseudo-class (như :hover, :focus, :nth-child) chọn phần tử dựa trên trạng thái hoặc vị trí đặc biệt của nó. Pseudo-element (như ::before, ::after) cho phép tạo và định dạng một phần nội dung ảo gắn thêm vào phần tử mà không cần thêm thẻ HTML thật.
INSERT INTO lessons (id, chapter_id, course_id, title, order_index, type, content_text, duration_seconds, is_preview, video_status, video_s3_key, hls_manifest_url, created_at, updated_at, is_draft, pending_delete, draft_title, draft_content_text, quiz_id, deleted_at) VALUES ('49828e55-c3ab-4d0c-a5da-167406d5a56a', '1dff8c41-332a-4f31-a78d-2189fdb0fea6', '67407332-b3c5-4f37-8559-d39404b0a5ef', 'Hiệu Ứng, !important & Kỹ Thuật Nâng Cao', 3, 'TEXT', '!important ghi đè lên mọi quy tắc CSS khác bất kể độ đặc hiệu (specificity) hay thứ tự khai báo — nên hạn chế sử dụng vì gây khó khăn khi debug và bảo trì về sau, chỉ dùng trong trường hợp thực sự cần thiết (như override style của thư viện bên thứ ba). CSS Transition và Animation (@keyframes) cho phép tạo hiệu ứng chuyển động mượt mà (tweening) giữa các trạng thái CSS mà không cần JavaScript.
INSERT INTO course_versions (id, course_id, version_number, status, snapshot, change_summary, rejection_reason, submitted_by, reviewed_by, submitted_at, reviewed_at, label) VALUES ('719cf4e6-4ed1-41a5-8dcd-b4ddb3a7bf91', '4e44882d-fb2d-4e1c-91dc-87a80f0a83cc', 1, 'PENDING', '{"title":"Lập Trình Hướng Đối Tượng (OOP) & Nguyên Tắc SOLID","description":"Hệ thống hóa toàn diện kiến thức OOP: lớp, đối tượng, constructor, bốn tính chất cốt lõi (đóng gói, kế thừa, đa hình, trừu tượng), quản lý ngoại lệ và bộ nhớ, cùng 5 nguyên tắc thiết kế SOLID giúp mã nguồn linh hoạt, dễ bảo trì và mở rộng. Minh họa bằng Java.","level":"INTERMEDIATE","thumbnailUrl":null,"categoryName":null,"chapters":[{"title":"Nền Tảng Lập Trình Hướng Đối Tượng","orderIndex":1,"lessons":[{"title":"Lớp, Đối Tượng & Constructor","lessonType":"TEXT","contentText":"Lớp (Class) là bản thiết kế (blueprint) mô tả thuộc tính và phương thức mà đối tượng tạo ra từ nó sẽ sở hữu — bản thân lớp không chiếm bộ nhớ Heap, chỉ được tải vào Metaspace để lưu metadata cấu trúc. Đối tượng (Object) là thực thể cụ thể (instance) được tạo bằng từ khóa new, được cấp phát bộ nhớ trên Heap.\n\nKhông phải lúc nào cũng cần tạo đối tượng: lớp Utility chỉ chứa phương thức tĩnh (như java.lang.Math) gọi trực tiếp qua tên lớp; mẫu thiết kế Singleton chỉ có một thực thể dùng chung; Abstract Class và Interface không thể khởi tạo trực tiếp. Constructor là phương thức đặc biệt, tên trùng với tên lớp, không có kiểu trả về, được gọi tự động khi tạo đối tượng mới; nếu không định nghĩa, trình biên dịch tự tạo constructor mặc định không tham số.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Bốn Tính Chất Cốt Lõi Của OOP","lessonType":"TEXT","contentText":"Tính đóng gói (Encapsulation): che giấu chi tiết bên trong đối tượng, chỉ tiếp cận qua giao diện public — triển khai bằng private kết hợp Getter/Setter kèm logic kiểm tra.\n\nTính kế thừa (Inheritance): lớp con tái sử dụng/mở rộng lớp cha theo quan hệ \"IS-A\". Hạn chế: gắn kết chặt chẽ (thay đổi lớp cha ảnh hưởng lớp con), vi phạm đóng gói qua protected, và Java/C# không hỗ trợ đa kế thừa Class (chỉ qua Interface) để tránh Diamond Problem.\n\nTính đa hình (Polymorphism): một đối tượng/phương thức thể hiện nhiều hình thức tùy ngữ cảnh. Overloading (nạp chồng) xảy ra trong cùng lớp, cùng tên khác chữ ký; Overriding (ghi đè) xảy ra giữa lớp cha-con, trùng hoàn toàn tên/tham số/kiểu trả về.\n\nTính trừu tượng (Abstraction): tập trung đặc điểm cốt lõi, bỏ qua chi tiết triển khai phức tạp — thực hiện qua Abstract Class (chứa cả phương thức trừu tượng lẫn cụ thể) và Interface (hợp đồng hành vi thuần túy, từ Java 8+ có thêm default/static method).","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"Ngoại Lệ & Quản Lý Bộ Nhớ (Garbage Collection)","lessonType":"TEXT","contentText":"Ngoại lệ (Exception) là sự kiện bất thường làm gián đoạn luồng chạy chương trình, chia làm Checked Exception (bắt buộc xử lý khi biên dịch) và Unchecked/Runtime Exception (xảy ra khi chạy). Xử lý bằng try (đoạn mã có nguy cơ lỗi) - catch (bắt và xử lý) - finally (luôn thực thi, dùng dọn tài nguyên); throw/throws dùng để ném hoặc chuyển tiếp trách nhiệm xử lý.\n\nGarbage Collection (GC) là tiến trình ngầm tự động của JVM, phát hiện và thu hồi vùng nhớ Heap của các đối tượng không còn được tham chiếu, giúp tránh rò rỉ bộ nhớ (Memory Leak) mà không cần giải phóng thủ công như C/C++. Về mặt cú pháp, Java bắt buộc mọi code phải nằm trong một Class, nhưng về tư duy, lập trình viên vẫn có thể viết theo phong cách thủ tục (Procedural) nếu không tận dụng kế thừa/đa hình/đóng gói — khi đó chỉ mượn vỏ bọc cú pháp OOP.","durationSeconds":null,"orderIndex":3,"resources":[]}]},{"title":"Nguyên Tắc Thiết Kế SOLID","orderIndex":2,"lessons":[{"title":"SRP & OCP — Đơn Nhiệm Và Đóng/Mở","lessonType":"TEXT","contentText":"Single Responsibility Principle (SRP): một lớp chỉ nên giữ một trách nhiệm duy nhất — chỉ một lý do để thay đổi. Ví dụ vi phạm: lớp Invoice vừa tính tiền, vừa in ấn, vừa lưu database. Giải pháp: tách thành Invoice, InvoicePrinter, InvoiceRepository độc lập.\n\nOpen/Closed Principle (OCP): thành phần phần mềm nên mở rộng được (Open for extension) nhưng đóng với việc sửa đổi mã nguồn có sẵn (Closed for modification). Ví dụ vi phạm: PaymentProcessor dùng if-else kiểm tra loại thẻ, mỗi lần thêm cổng thanh toán mới phải sửa hàm cũ. Giải pháp: định nghĩa interface PaymentMethod với processPayment(), mỗi cổng thanh toán là một lớp implement riêng — thêm tính năng chỉ cần thêm lớp mới.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"LSP & ISP — Thay Thế Liskov Và Phân Tách Giao Diện","lessonType":"TEXT","contentText":"Liskov Substitution Principle (LSP): đối tượng lớp con phải thay thế hoàn toàn được cho lớp cha mà không làm sai tính đúng đắn chương trình. Ví dụ vi phạm kinh điển: lớp cha Bird có fly(), lớp con Ostrich (đà điểu) không biết bay nên phải ném exception — vi phạm hợp đồng của lớp cha. Giải pháp: tách nhỏ phân cấp, chỉ loài bay được mới kế thừa interface FlyingBird riêng.\n\nInterface Segregation Principle (ISP): nên chia nhỏ giao diện lớn thành nhiều giao diện chuyên biệt, tránh ép lớp thực thi phải cài đặt phương thức không dùng đến. Ví dụ vi phạm: interface Worker có work(), eat(), code() — RobotWorker buộc phải viết hàm rỗng cho eat(). Giải pháp: tách thành Workable, Feedable, Codeable — Robot chỉ implement Workable.","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"DIP — Đảo Ngược Phụ Thuộc & Tổng Kết SOLID","lessonType":"TEXT","contentText":"Dependency Inversion Principle (DIP): module cấp cao không nên phụ thuộc trực tiếp vào module cấp thấp — cả hai nên phụ thuộc vào tầng trừu tượng (Interface). Ví dụ vi phạm: lớp Car khởi tạo trực tiếp MySQLDatabase trong constructor, hardcode phụ thuộc. Giải pháp: định nghĩa interface Database, Car nhận vào một đối tượng Database qua Dependency Injection — các lớp cụ thể như MySQLDatabase, OracleDatabase implement interface đó.\n\nTổng kết: SOLID giúp giảm phụ thuộc lẫn nhau (Loose Coupling), dễ mở rộng, dễ viết Unit Test nhờ cô lập qua Interface, tái sử dụng mã nguồn hiệu quả. Nhược điểm: tăng số lượng lớp/interface khiến dự án phức tạp hơn ở giai đoạn đầu, đòi hỏi tư duy thiết kế kiến trúc tốt, và có thể dẫn đến Over-engineering nếu áp dụng quá mức cho dự án nhỏ.","durationSeconds":null,"orderIndex":3,"resources":[]}]}]}', NULL, NULL, '00000000-0000-0000-0000-000000000002', NULL, '2026-07-13T01:29:19.608626+00:00'::timestamptz, NULL, NULL);
INSERT INTO course_versions (id, course_id, version_number, status, snapshot, change_summary, rejection_reason, submitted_by, reviewed_by, submitted_at, reviewed_at, label) VALUES ('016f8fd6-47b8-4c46-ae38-fa9b6afe052a', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 1, 'APPROVED', '{"title":"HTML & HTML5 Toàn Diện Cho Người Mới Bắt Đầu","description":"Khóa học toàn diện về HTML và HTML5: cú pháp thẻ/thuộc tính, cấu trúc tài liệu, tích hợp CSS/JavaScript, form nhập liệu, xử lý sự kiện, các tính năng nổi bật của HTML5 (Semantic Elements) và chuẩn SEO cơ bản.","level":"BEGINNER","thumbnailUrl":null,"categoryName":null,"chapters":[{"title":"Cú Pháp & Cấu Trúc Tài Liệu HTML","orderIndex":1,"lessons":[{"title":"Thẻ, Thuộc Tính & Các Thẻ Văn Bản Cơ Bản","lessonType":"TEXT","contentText":"Thẻ (Tag) là đơn vị cấu trúc cơ bản của HTML, thường đi theo cặp mở/đóng (<p></p>), một số thẻ tự đóng (<img />, <br />). Thuộc tính (Attribute) là thông tin bổ sung đặt trong thẻ mở, dạng name=\"value\" (như src, href, class, id), cung cấp thêm dữ liệu hoặc điều khiển hành vi của phần tử.\n\nThẻ <p> dùng cho đoạn văn bản thường; thẻ <h1> đến <h6> dùng cho tiêu đề với mức độ quan trọng giảm dần (h1 quan trọng nhất, chỉ nên dùng một lần cho tiêu đề chính của trang) — không nên dùng thẻ heading chỉ để làm chữ to mà bỏ qua ý nghĩa ngữ nghĩa/SEO. Thuộc tính id định danh DUY NHẤT một phần tử trong toàn trang (dùng cho JavaScript/CSS cụ thể), trong khi class có thể gán cho NHIỀU phần tử để áp dụng chung một style. Thẻ <strong> và <b> đều làm chữ đậm nhưng <strong> mang ý nghĩa ngữ nghĩa \"quan trọng\" (tốt cho SEO/trình đọc màn hình), còn <b> chỉ là định dạng thị giác thuần túy; tương tự <em> (nhấn mạnh ngữ nghĩa) so với <i> (chữ nghiêng thuần túy).","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Cấu Trúc Head/Body, Bảng & Layout","lessonType":"TEXT","contentText":"Thẻ <head> chứa metadata không hiển thị trực tiếp trên trang (title, meta charset, meta viewport, liên kết CSS, SEO description) — quan trọng cho trình duyệt và công cụ tìm kiếm. Thẻ <body> chứa toàn bộ nội dung hiển thị thực sự cho người dùng (văn bản, hình ảnh, form, bảng...).\n\nBảng HTML (<table>) gồm <tr> (hàng), <td> (ô dữ liệu), <th> (ô tiêu đề). Để ghép nhiều hàng hoặc cột thành một ô lớn, dùng thuộc tính colspan (ghép cột) hoặc rowspan (ghép hàng) trên thẻ <td>/<th>. Về phân loại hiển thị: Inline element (như <span>, <a>) không tự xuống dòng và chỉ chiếm đúng kích thước nội dung; Block element (như <div>, <p>) luôn chiếm trọn chiều ngang và tự xuống dòng — có thể chuyển đổi qua lại giữa hai loại này bằng thuộc tính CSS display.","durationSeconds":null,"orderIndex":2,"resources":[]}]},{"title":"Liên Kết, Tích Hợp CSS/JavaScript & Form","orderIndex":2,"lessons":[{"title":"Liên Kết & Tích Hợp CSS","lessonType":"TEXT","contentText":"Liên kết trong HTML dùng thẻ <a href=\"...\">, thuộc tính target=\"_blank\" mở liên kết ở tab mới. Có 3 cách tích hợp CSS với HTML: Inline CSS (viết trực tiếp trong thuộc tính style của thẻ, ưu tiên cao nhất nhưng khó bảo trì), Internal CSS (khai báo trong thẻ <style> ở phần <head>, áp dụng riêng cho trang đó), và External CSS (liên kết file .css riêng qua thẻ <link rel=\"stylesheet\" href=\"...\">, cách được khuyến nghị vì dễ tái sử dụng và bảo trì trên nhiều trang).\n\nThẻ <link> dùng để liên kết tài nguyên bên ngoài vào trang (CSS, favicon...) và đặt trong <head>, không hiển thị nội dung; trong khi thẻ <a> tạo siêu liên kết (hyperlink) có thể nhấp được, hiển thị trực tiếp trong nội dung <body> để điều hướng người dùng đến trang/tài nguyên khác.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Tích Hợp JavaScript & Xử Lý Sự Kiện","lessonType":"TEXT","contentText":"Có thể thêm JavaScript vào HTML qua 3 cách tương tự CSS: Inline (trong thuộc tính onclick...), Internal (trong thẻ <script> ngay trong trang), External (liên kết file .js riêng qua <script src=\"...\">). Vị trí đặt thẻ <script>: nếu đặt trong <head>, trình duyệt phải tải và chạy xong script mới tiếp tục dựng trang (có thể làm chậm hiển thị) trừ khi dùng thuộc tính defer/async; đặt cuối <body> (trước </body>) là thông lệ phổ biến để đảm bảo toàn bộ DOM đã dựng xong trước khi script chạy, tránh lỗi truy cập phần tử chưa tồn tại.\n\nXử lý sự kiện (Event Handling) cho phép chương trình phản ứng với hành động người dùng (click, submit, mouseover, keydown...) thông qua các event listener gắn vào phần tử HTML, thường thiết lập bằng JavaScript (addEventListener) thay vì thuộc tính onclick inline để tách biệt logic khỏi cấu trúc (đúng tinh thần Separation of Concerns).","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"Form & Các Kiểu Input","lessonType":"TEXT","contentText":"Form trong HTML dùng thẻ <form action=\"...\" method=\"post|get\"> để thu thập dữ liệu người dùng và gửi lên server. Các phần tử nhập liệu phổ biến: <input>, <textarea>, <select>, <button>. HTML5 bổ sung nhiều kiểu input mới giúp validate và trải nghiệm nhập liệu tốt hơn ngay từ trình duyệt mà không cần JavaScript: type=\"email\" (kiểm tra định dạng email), type=\"date\" (bộ chọn ngày), type=\"number\" (chỉ nhập số, có nút tăng/giảm), type=\"range\" (thanh trượt), type=\"tel\", type=\"url\", type=\"color\"... Các thuộc tính bổ trợ như required, placeholder, pattern giúp tăng cường validate phía client trước khi gửi dữ liệu lên server.","durationSeconds":null,"orderIndex":3,"resources":[]}]},{"title":"HTML5 & Chuẩn SEO","orderIndex":3,"lessons":[{"title":"Tính Năng Mới Của HTML5 & Semantic Elements","lessonType":"TEXT","contentText":"HTML5 mang lại nhiều ưu điểm đột phá so với phiên bản trước: hỗ trợ đa phương tiện gốc (<video>, <audio>) không cần plugin Flash; các API mới (Canvas, Geolocation, Local Storage, Web Workers); cú pháp gọn nhẹ hơn (<!DOCTYPE html>); và đặc biệt là Semantic Elements — các thẻ mang ý nghĩa ngữ nghĩa rõ ràng về vai trò của khối nội dung thay vì chỉ dùng <div> chung chung: <header> (đầu trang), <nav> (menu điều hướng), <main> (nội dung chính), <article> (bài viết độc lập), <section> (một phần nội dung theo chủ đề), <aside> (nội dung phụ/sidebar), <footer> (chân trang). Semantic Elements giúp trình duyệt, công cụ tìm kiếm và trình đọc màn hình (screen reader) hiểu đúng cấu trúc và vai trò từng phần của trang, cải thiện đáng kể khả năng tiếp cận (accessibility) và SEO.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"SEO & Cấu Trúc HTML Chuẩn","lessonType":"TEXT","contentText":"SEO (Search Engine Optimization) là tập hợp kỹ thuật giúp trang web được các công cụ tìm kiếm (Google...) đánh giá cao và xếp hạng tốt hơn trong kết quả tìm kiếm. Để có cấu trúc HTML chuẩn SEO, cần: sử dụng đúng phân cấp thẻ heading (chỉ một <h1> duy nhất cho tiêu đề chính, các heading con theo thứ tự h2, h3... không nhảy cóc); khai báo đầy đủ <meta name=\"description\"> mô tả ngắn gọn nội dung trang; dùng Semantic Elements thay vì <div> tràn lan để công cụ tìm kiếm hiểu đúng cấu trúc; thêm thuộc tính alt cho mọi thẻ <img> (vừa hỗ trợ accessibility vừa giúp SEO hình ảnh); đảm bảo trang responsive (thân thiện di động) và tốc độ tải nhanh — đây đều là các yếu tố xếp hạng quan trọng của công cụ tìm kiếm hiện đại.","durationSeconds":null,"orderIndex":2,"resources":[]}]}]}', NULL, NULL, '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000001', '2026-07-13T01:31:27.065993+00:00'::timestamptz, '2026-07-13T01:31:42.142504+00:00'::timestamptz, NULL);
INSERT INTO course_versions (id, course_id, version_number, status, snapshot, change_summary, rejection_reason, submitted_by, reviewed_by, submitted_at, reviewed_at, label) VALUES ('eafc497e-f930-4b51-a21e-216fb0c666fa', '513ccfd5-8642-4286-b1ba-b85e6bc1a72f', 2, 'REJECTED', '{"title":"HTML & HTML5 Toàn Diện Cho Người Mới Bắt Đầu","description":"Khóa học toàn diện về HTML và HTML5: cú pháp thẻ/thuộc tính, cấu trúc tài liệu, tích hợp CSS/JavaScript, form nhập liệu, xử lý sự kiện, các tính năng nổi bật của HTML5 (Semantic Elements) và chuẩn SEO cơ bản.","level":"BEGINNER","thumbnailUrl":null,"categoryName":null,"chapters":[{"title":"Cú Pháp & Cấu Trúc Tài Liệu HTML","orderIndex":1,"lessons":[{"title":"Thẻ, Thuộc Tính & Các Thẻ Văn Bản Cơ Bản","lessonType":"TEXT","contentText":"Thẻ (Tag) là đơn vị cấu trúc cơ bản của HTML, thường đi theo cặp mở/đóng (<p></p>), một số thẻ tự đóng (<img />, <br />). Thuộc tính (Attribute) là thông tin bổ sung đặt trong thẻ mở, dạng name=\"value\" (như src, href, class, id), cung cấp thêm dữ liệu hoặc điều khiển hành vi của phần tử.\n\nThẻ <p> dùng cho đoạn văn bản thường; thẻ <h1> đến <h6> dùng cho tiêu đề với mức độ quan trọng giảm dần (h1 quan trọng nhất, chỉ nên dùng một lần cho tiêu đề chính của trang) — không nên dùng thẻ heading chỉ để làm chữ to mà bỏ qua ý nghĩa ngữ nghĩa/SEO. Thuộc tính id định danh DUY NHẤT một phần tử trong toàn trang (dùng cho JavaScript/CSS cụ thể), trong khi class có thể gán cho NHIỀU phần tử để áp dụng chung một style. Thẻ <strong> và <b> đều làm chữ đậm nhưng <strong> mang ý nghĩa ngữ nghĩa \"quan trọng\" (tốt cho SEO/trình đọc màn hình), còn <b> chỉ là định dạng thị giác thuần túy; tương tự <em> (nhấn mạnh ngữ nghĩa) so với <i> (chữ nghiêng thuần túy).","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Cấu Trúc Head/Body, Bảng & Layout","lessonType":"TEXT","contentText":"Thẻ <head> chứa metadata không hiển thị trực tiếp trên trang (title, meta charset, meta viewport, liên kết CSS, SEO description) — quan trọng cho trình duyệt và công cụ tìm kiếm. Thẻ <body> chứa toàn bộ nội dung hiển thị thực sự cho người dùng (văn bản, hình ảnh, form, bảng...).\n\nBảng HTML (<table>) gồm <tr> (hàng), <td> (ô dữ liệu), <th> (ô tiêu đề). Để ghép nhiều hàng hoặc cột thành một ô lớn, dùng thuộc tính colspan (ghép cột) hoặc rowspan (ghép hàng) trên thẻ <td>/<th>. Về phân loại hiển thị: Inline element (như <span>, <a>) không tự xuống dòng và chỉ chiếm đúng kích thước nội dung; Block element (như <div>, <p>) luôn chiếm trọn chiều ngang và tự xuống dòng — có thể chuyển đổi qua lại giữa hai loại này bằng thuộc tính CSS display.","durationSeconds":null,"orderIndex":2,"resources":[]}]},{"title":"Liên Kết, Tích Hợp CSS/JavaScript & Form","orderIndex":2,"lessons":[{"title":"Liên Kết & Tích Hợp CSS","lessonType":"TEXT","contentText":"Liên kết trong HTML dùng thẻ <a href=\"...\">, thuộc tính target=\"_blank\" mở liên kết ở tab mới. Có 3 cách tích hợp CSS với HTML: Inline CSS (viết trực tiếp trong thuộc tính style của thẻ, ưu tiên cao nhất nhưng khó bảo trì), Internal CSS (khai báo trong thẻ <style> ở phần <head>, áp dụng riêng cho trang đó), và External CSS (liên kết file .css riêng qua thẻ <link rel=\"stylesheet\" href=\"...\">, cách được khuyến nghị vì dễ tái sử dụng và bảo trì trên nhiều trang).\n\nThẻ <link> dùng để liên kết tài nguyên bên ngoài vào trang (CSS, favicon...) và đặt trong <head>, không hiển thị nội dung; trong khi thẻ <a> tạo siêu liên kết (hyperlink) có thể nhấp được, hiển thị trực tiếp trong nội dung <body> để điều hướng người dùng đến trang/tài nguyên khác.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Tích Hợp JavaScript & Xử Lý Sự Kiện","lessonType":"TEXT","contentText":"Có thể thêm JavaScript vào HTML qua 3 cách tương tự CSS: Inline (trong thuộc tính onclick...), Internal (trong thẻ <script> ngay trong trang), External (liên kết file .js riêng qua <script src=\"...\">). Vị trí đặt thẻ <script>: nếu đặt trong <head>, trình duyệt phải tải và chạy xong script mới tiếp tục dựng trang (có thể làm chậm hiển thị) trừ khi dùng thuộc tính defer/async; đặt cuối <body> (trước </body>) là thông lệ phổ biến để đảm bảo toàn bộ DOM đã dựng xong trước khi script chạy, tránh lỗi truy cập phần tử chưa tồn tại.\n\nXử lý sự kiện (Event Handling) cho phép chương trình phản ứng với hành động người dùng (click, submit, mouseover, keydown...) thông qua các event listener gắn vào phần tử HTML, thường thiết lập bằng JavaScript (addEventListener) thay vì thuộc tính onclick inline để tách biệt logic khỏi cấu trúc (đúng tinh thần Separation of Concerns).","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"Form & Các Kiểu Input","lessonType":"TEXT","contentText":"Form trong HTML dùng thẻ <form action=\"...\" method=\"post|get\"> để thu thập dữ liệu người dùng và gửi lên server. Các phần tử nhập liệu phổ biến: <input>, <textarea>, <select>, <button>. HTML5 bổ sung nhiều kiểu input mới giúp validate và trải nghiệm nhập liệu tốt hơn ngay từ trình duyệt mà không cần JavaScript: type=\"email\" (kiểm tra định dạng email), type=\"date\" (bộ chọn ngày), type=\"number\" (chỉ nhập số, có nút tăng/giảm), type=\"range\" (thanh trượt), type=\"tel\", type=\"url\", type=\"color\"... Các thuộc tính bổ trợ như required, placeholder, pattern giúp tăng cường validate phía client trước khi gửi dữ liệu lên server.","durationSeconds":null,"orderIndex":3,"resources":[]}]},{"title":"HTML5 & Chuẩn SEO","orderIndex":3,"lessons":[{"title":"Tính Năng Mới Của HTML5 & Semantic Elements","lessonType":"TEXT","contentText":"HTML5 mang lại nhiều ưu điểm đột phá so với phiên bản trước: hỗ trợ đa phương tiện gốc (<video>, <audio>) không cần plugin Flash; các API mới (Canvas, Geolocation, Local Storage, Web Workers); cú pháp gọn nhẹ hơn (<!DOCTYPE html>); và đặc biệt là Semantic Elements — các thẻ mang ý nghĩa ngữ nghĩa rõ ràng về vai trò của khối nội dung thay vì chỉ dùng <div> chung chung: <header> (đầu trang), <nav> (menu điều hướng), <main> (nội dung chính), <article> (bài viết độc lập), <section> (một phần nội dung theo chủ đề), <aside> (nội dung phụ/sidebar), <footer> (chân trang). Semantic Elements giúp trình duyệt, công cụ tìm kiếm và trình đọc màn hình (screen reader) hiểu đúng cấu trúc và vai trò từng phần của trang, cải thiện đáng kể khả năng tiếp cận (accessibility) và SEO.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"SEO & Cấu Trúc HTML Chuẩn","lessonType":"TEXT","contentText":"SEO (Search Engine Optimization) là tập hợp kỹ thuật giúp trang web được các công cụ tìm kiếm (Google...) đánh giá cao và xếp hạng tốt hơn trong kết quả tìm kiếm. Để có cấu trúc HTML chuẩn SEO, cần: sử dụng đúng phân cấp thẻ heading (chỉ một <h1> duy nhất cho tiêu đề chính, các heading con theo thứ tự h2, h3... không nhảy cóc); khai báo đầy đủ <meta name=\"description\"> mô tả ngắn gọn nội dung trang; dùng Semantic Elements thay vì <div> tràn lan để công cụ tìm kiếm hiểu đúng cấu trúc; thêm thuộc tính alt cho mọi thẻ <img> (vừa hỗ trợ accessibility vừa giúp SEO hình ảnh); đảm bảo trang responsive (thân thiện di động) và tốc độ tải nhanh — đây đều là các yếu tố xếp hạng quan trọng của công cụ tìm kiếm hiện đại.\n\n[Bản nháp] Bổ sung thêm phần Core Web Vitals (LCP, FID, CLS) như các chỉ số kỹ thuật quan trọng Google dùng để đánh giá trải nghiệm người dùng và xếp hạng SEO.","durationSeconds":null,"orderIndex":2,"resources":[]}]}]}', NULL, 'Nội dung Core Web Vitals cần bổ sung ví dụ đo lường thực tế và số liệu cụ thể trước khi duyệt.', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000001', '2026-07-13T01:34:07.840694+00:00'::timestamptz, '2026-07-13T01:34:29.269506+00:00'::timestamptz, NULL);
INSERT INTO course_versions (id, course_id, version_number, status, snapshot, change_summary, rejection_reason, submitted_by, reviewed_by, submitted_at, reviewed_at, label) VALUES ('fc916000-7bdb-445d-b0f9-bbc67ba56ea3', '669edabb-a426-4247-ad75-2d8d168bc0a6', 1, 'APPROVED', '{"title":"Cấu Trúc Dữ Liệu & Giải Thuật Toàn Diện","description":"Khóa học hệ thống hóa kiến thức về cấu trúc dữ liệu và giải thuật, từ cơ chế lưu trữ bộ nhớ, cấu trúc tuyến tính (mảng, danh sách liên kết, stack, queue), bảng băm, cây/heap cho đến đồ thị và các thuật toán duyệt phổ biến (BFS/DFS). Phù hợp cho người chuẩn bị phỏng vấn kỹ thuật hoặc muốn củng cố nền tảng lập trình.","level":"INTERMEDIATE","thumbnailUrl":null,"categoryName":null,"chapters":[{"title":"Bộ Nhớ & Cấu Trúc Dữ Liệu Tuyến Tính","orderIndex":1,"lessons":[{"title":"Cơ Chế Lưu Trữ Bộ Nhớ","lessonType":"TEXT","contentText":"Khi một biến được khai báo và khởi tạo, hệ thống trải qua 4 bước: (1) Xác định kiểu dữ liệu và kích thước byte cần thiết (int chiếm 4 bytes, double chiếm 8 bytes); (2) Cấp phát địa chỉ bộ nhớ — biến cục bộ và tham chiếu vào Stack (nhanh, tự giải phóng khi hết block lệnh), đối tượng và mảng vào Heap (vùng nhớ động, tồn tại lâu hơn); (3) Liên kết định danh và địa chỉ qua Symbol Table, ánh xạ tên biến với địa chỉ ô nhớ dạng Hexadecimal; (4) Ghi giá trị dưới dạng mã nhị phân vào các ô nhớ đã chỉ định. Hiểu rõ cơ chế Stack vs Heap là nền tảng để lý giải hiệu năng và vòng đời của mọi cấu trúc dữ liệu sau này.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Mảng & Danh Sách Liên Kết","lessonType":"TEXT","contentText":"Mảng (Array) là cấu trúc dữ liệu tuyến tính lưu các phần tử cùng kiểu tại các ô nhớ liên tiếp, kích thước cố định (Static). Truy cập ngẫu nhiên đạt O(1) nhờ công thức: Địa chỉ phần tử i = Địa chỉ gốc + i × kích thước kiểu dữ liệu. Mảng đa chiều thực chất là \"mảng của mảng\", được trải phẳng và lưu tuần tự theo Row-major hoặc Column-major trên RAM.\n\nDanh sách liên kết (Linked List) là cấu trúc tuyến tính động, gồm các Node (Data + con trỏ Next) không nằm liên tiếp trong bộ nhớ. Mảng vượt trội khi cần truy cập ngẫu nhiên (O(1) so với O(n) của Linked List); Linked List vượt trội khi cần chèn/xóa liên tục ở đầu hoặc giữa danh sách (O(1) nếu biết vị trí, so với O(n) của mảng do phải dịch chuyển phần tử). Danh sách liên kết đôi (Doubly Linked List) bổ sung con trỏ Previous, cho phép duyệt hai chiều với chi phí bộ nhớ cao hơn.","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"Ngăn Xếp (Stack) & Hàng Đợi (Queue)","lessonType":"TEXT","contentText":"Ngăn xếp (Stack) hoạt động theo nguyên lý LIFO (Last In, First Out) với 3 thao tác chính: push() (thêm vào đỉnh), pop() (xóa ở đỉnh), peek() (xem đỉnh mà không xóa). Ứng dụng thực tế: hàm đệ quy, tính năng Undo/Redo, kiểm tra tính hợp lệ của dấu ngoặc.\n\nHàng đợi (Queue) hoạt động theo nguyên lý FIFO (First In, First Out) với enqueue() (thêm vào cuối - Rear) và dequeue() (xóa từ đầu - Front). Ứng dụng: hệ thống in ấn (Print Spooler), hàng đợi tin nhắn (Message Queue), bộ đệm dữ liệu. Điểm khác biệt cốt lõi: Stack chỉ thao tác tại một đầu (Top), trong khi Queue thao tác ở hai đầu khác nhau (vào Rear, ra Front).","durationSeconds":null,"orderIndex":3,"resources":[]}]},{"title":"Cấu Trúc Phi Tuyến Tính & Đồ Thị","orderIndex":2,"lessons":[{"title":"Bảng Băm (Hash Table)","lessonType":"TEXT","contentText":"HashMap là cấu trúc dữ liệu thuộc Java Collections Framework, lưu trữ theo cặp Key-Value, cho phép truy cập/thêm/xóa với hiệu năng trung bình O(1) nhờ cơ chế băm (Hashing). Cơ chế hoạt động: hàm hashCode() biến Key thành chỉ số (Index) để xếp vào các Bucket trong mảng ngầm định. Khi hai Key khác nhau cho cùng chỉ số, xảy ra Xung đột băm (Hash Collision) — Java giải quyết bằng Linked List tại bucket đó, và tự động nâng cấp thành Cây đỏ đen (Red-Black Tree) nếu số phần tử xung đột vượt quá 8 (từ Java 8) để giữ hiệu năng tìm kiếm O(log n).","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Cây (Tree) & Heap","lessonType":"TEXT","contentText":"Cây là cấu trúc dữ liệu phi tuyến tính, phân cấp, gồm các Node nối bằng Edge, luôn có một Root Node duy nhất, các Node không có con gọi là Leaf Node. Cây nhị phân (Binary Tree): mỗi Node cha có tối đa 2 con (Left/Right Child). Cây tìm kiếm nhị phân (BST) thêm ràng buộc: giá trị cây con trái < giá trị nút cha ≤ giá trị cây con phải, giúp tìm kiếm/chèn/xóa đạt O(log n) khi cân bằng.\n\nHeap là cây nhị phân gần hoàn chỉnh thỏa Heap Property, biểu diễn bằng mảng ngầm định: Max-Heap (nút cha ≥ nút con, gốc là phần tử lớn nhất) và Min-Heap (nút cha ≤ nút con, gốc là phần tử nhỏ nhất). Heap là nền tảng cho thuật toán Heapsort và cấu trúc Priority Queue.","durationSeconds":null,"orderIndex":2,"resources":[]},{"title":"Đồ Thị (Graph) & Thuật Toán BFS/DFS","lessonType":"TEXT","contentText":"Đồ thị (Graph) gồm tập đỉnh (Vertices) và tập cạnh (Edges) nối các cặp đỉnh, có thể có hướng (Directed) hoặc vô hướng (Undirected). Ứng dụng: mạng xã hội, bản đồ/định vị, mạng máy tính, hệ thống gợi ý. Hai cách biểu diễn phổ biến: Ma trận kề (Adjacency Matrix — kiểm tra cạnh O(1) nhưng tốn O(V²) bộ nhớ) và Danh sách kề (Adjacency List — tối ưu bộ nhớ hơn cho đồ thị thưa).\n\nBFS (Breadth First Search) duyệt theo từng lớp, dùng cấu trúc Queue để quản lý các nút chờ duyệt. DFS (Depth First Search) duyệt sâu nhất có thể theo mỗi nhánh trước khi quay lui, dùng Stack hoặc đệ quy hệ thống. DFS tối ưu hơn khi bộ nhớ hạn chế (branching factor lớn), khi cần duyệt hết mọi cấu hình (mê cung, sudoku), hoặc chỉ cần kiểm tra tính kết nối giữa hai đỉnh.","durationSeconds":null,"orderIndex":3,"resources":[]}]}]}', NULL, NULL, '00000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000001', '2026-07-13T01:27:09.580880+00:00'::timestamptz, '2026-07-13T01:27:10.179477+00:00'::timestamptz, NULL);
INSERT INTO course_versions (id, course_id, version_number, status, snapshot, change_summary, rejection_reason, submitted_by, reviewed_by, submitted_at, reviewed_at, label) VALUES ('8e420811-619d-462c-a39c-a7ac3800b5c4', '669edabb-a426-4247-ad75-2d8d168bc0a6', 2, 'APPROVED', '{"title":"Cấu Trúc Dữ Liệu & Giải Thuật Toàn Diện","description":"Khóa học hệ thống hóa kiến thức về cấu trúc dữ liệu và giải thuật, từ cơ chế lưu trữ bộ nhớ, cấu trúc tuyến tính (mảng, danh sách liên kết, stack, queue), bảng băm, cây/heap cho đến đồ thị và các thuật toán duyệt phổ biến (BFS/DFS). Phù hợp cho người chuẩn bị phỏng vấn kỹ thuật hoặc muốn củng cố nền tảng lập trình.","level":"INTERMEDIATE","thumbnailUrl":null,"categoryName":null,"chapters":[{"title":"Bộ Nhớ & Cấu Trúc Dữ Liệu Tuyến Tính","orderIndex":1,"lessons":[{"title":"Cơ Chế Lưu Trữ Bộ Nhớ","lessonType":"TEXT","contentText":"Khi một biến được khai báo và khởi tạo, hệ thống trải qua 4 bước: (1) Xác định kiểu dữ liệu và kích thước byte cần thiết (int chiếm 4 bytes, double chiếm 8 bytes); (2) Cấp phát địa chỉ bộ nhớ — biến cục bộ và tham chiếu vào Stack (nhanh, tự giải phóng khi hết block lệnh), đối tượng và mảng vào Heap (vùng nhớ động, tồn tại lâu hơn); (3) Liên kết định danh và địa chỉ qua Symbol Table, ánh xạ tên biến với địa chỉ ô nhớ dạng Hexadecimal; (4) Ghi giá trị dưới dạng mã nhị phân vào các ô nhớ đã chỉ định. Hiểu rõ cơ chế Stack vs Heap là nền tảng để lý giải hiệu năng và vòng đời của mọi cấu trúc dữ liệu sau này.\n\n[Cập nhật v2] Bổ sung: trong các JVM hiện đại, cơ chế Escape Analysis còn có thể tối ưu để cấp phát một số đối tượng cục bộ trực tiếp trên Stack thay vì Heap nếu chứng minh được đối tượng không \"thoát\" ra khỏi phạm vi phương thức, giúp giảm áp lực cho Garbage Collector.","durationSeconds":null,"orderIndex":1,"resources":[]},{"title":"Mảng & Danh Sách Liên Kết","lessonType":"TEXT","contentText":"Mảng (Array) là cấu trúc dữ liệu tuyến tính lưu các phần tử cùng kiểu tại các ô nhớ liên tiếp, kích thước cố